TASK_RESP=$(curl -s -X POST https://dashscope.aliyuncs.com/api/v1/services/aigc/text2image/image-synthesis \
  -H "Authorization: Bearer ${DASHSCOPE_API_KEY}" \
  -H "Content-Type: application/json" \
  -d '{
    "model": "wanx2.1-t2i-turbo",
    "input": {
      "prompt": "山水画，中国传统水墨风格，远山含黛，近水如镜，云雾缭绕，松柏苍翠，意境悠远，高画质"
    },
    "parameters": {
      "size": "1024*1024",
      "n": 1
    }
  }')

echo "Response: $TASK_RESP"
